scwin.gridColumnOrder;

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd     = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                     //소속자회사
    scwin.vLoginCoClsCd  = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];               //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"];   //사용자소속구분코드
    scwin.isSubCompany   = false;
    scwin.privAdmin      = $c.gus.cfIsNull(scwin.memJson["privAdmin"]) ? "" : scwin.memJson["privAdmin"];           //관리자권한
    scwin.first = 0;

    /**
     * TODO : 임시로 회사코드 초기값 가지고 있기 위해 처리
     * 로드 시 마지막으로 처리되는 로직
     */
    const codeOptions = [
        { grpCd: "EQ055", compID: "" }
    ];
    $c.data.setCommonCode(codeOptions, scwin.callBackCommonCode);
};

/**
 * $c.data.setCommonCode 함수의 콜백함수
 */
scwin.callBackCommonCode = function() {
    scwin.initJson = dma_search.getJSON();
};

/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    gr_master.setNoResultMessageVisible(false);
    ds_master.removeAll();
    ds_masterHeader.removeAll();
    ds_crossTab.removeAll();
    totalRows.setValue("0");
    pgl_msgpageList.hide();

    //그리드헤더 초기화
    for(let i=1; i<=50; i++) {
        gr_master.setHeaderValue("h_col"+i, "");
        gr_master.setColumnVisible("col"+i, false);
    }
    gr_master.setColumnVisible("subTotal", false);
};


/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    scwin.gridColumnOrder = gr_master.getColumnOrder(); // 초기 순서 저장
    scwin.setInit();
    scwin.f_HeaderCreate();
    $c.gus.cfDisableKey();
    scwin.f_FieldClear();
    scwin.f_setCompanyInfo();
};

/**
 * 조회필드 CLEAR
 */
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search, [ica_srchStdYm, rd_srchBookKndCd, lc_version, ed_coCd, ed_coNm]);
    //dma_search.setJSON(scwin.initJson);
    scwin.f_SetSrchDefault();
};

/**
 * 조회 기본값 설정
 */
scwin.f_SetSrchDefault = function() {
    rd_srchBookKndCd.setValue("613");
    scwin.closeYm = $c.date.getServerDateTime().substring(0,6);
    ica_srchStdYm.setValue(scwin.closeYm);
    scwin.f_GetVersion();
    ica_srchStdYm.focus();
};

