/**
 * 페이지정보를 구한다.
 */
scwin.f_GetPage = async function () {
    // ds_page.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC" +
    //     "&queryId=retrieveBookPageInfo" +
    //     "&param1 = " + rd_srchBookKndCd.getValue();
    // ds_page.undoAll();
    dma_search.set("sysCd"  , "CommonEBC");
    dma_search.set("queryId", "retrieveBookPageInfo");
    dma_search.set("param1" , rd_srchBookKndCd.getValue());
    ds_page.removeAll();
    let ret = await $c.sbm.execute(sbm_retrieveCommonPopup);
    ds_page.setJSON(ret.responseJSON.GAUCE);
    ds_page.sort("col1", 0);
    ds_page.reform();
};

/**
 * 조회버튼
 */
scwin.f_Retrieve = async function () {
    let ret = await $c.gus.cfValidate([tbl_search]);
    if (!ret) {
        return false;
    }
    if(ica_srchStdYm.getValue().length != 6){
        await $c.win.alert("마감년월은(는) 6자리수만큼 입력하십시오.");
        ica_srchStdYm.focus();
        return;
    }
    ret = await $c.date.isDate(ica_srchStdYm.getValue()+"01");
    if(!ret) {
        await $c.win.alert("올바른 마감년월을(를) 입력하십시오.");
        ica_srchStdYm.focus();
        return;
    }

    scwin.setInit();
    gr_master.setColumnOrder(scwin.gridColumnOrder);

    //이거진짜 페이지만 가져오는건데
    await scwin.f_GetPage();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_master.setNoResultMessageVisible(true);
    let rowCnt = ds_master.getRowCount();
    if (rowCnt > 0) {
        //sort 처리
        var options = {};
        options.sortIndex = "pageNo asetCostCdNm colNo";
        options.sortOrder = "1 1 1";     //오른차순:"1", 내림차순"-1"
        ds_master.multisort(options);
        ds_master.reform();
        //총계는 회계부서코드 중복 뺀값
        let rowCnt = ds_master.getColumnDistinctDataArray("asetCostCd").length;           
        totalRows.setValue(rowCnt);

        //크로스데이터리스트만들기
        scwin.makeCrossTab("1");
        //페이징 갯수 세팅
        pgl_msgpageList.show("");
        pgl_msgpageList.setCount(ds_page.getRowCount());

        gr_master.setFocusedCell(0, 0);

    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다
    }
};

scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg)
};

/**
 * pagelist에서 페이지가 변화했을 때
 */
scwin.pgl_msgpageList_onchange = function (current, before) {
    //그리드헤더 초기화
    for(let i=1; i<=50; i++) {
        gr_master.setHeaderValue("h_col"+i, "");
        gr_master.setColumnVisible("col"+i, false);
    }
    gr_master.setColumnVisible("subTotal", false);
    scwin.makeCrossTab(current+"");
};

/**
 * 크로스 데이터리스트 만들기(page처리시)
 */
scwin.makeCrossTab = function(page) {
    /**
     * 1. 그리드헤더정보 셋팅(hidden 보이기)
     */
    ds_masterHeader.removeAll();
    let mData = ds_master.getMatchedJSON("pageNo", page);
    for(let i=0; i<mData.length; i++) {
        let m    = mData[i];
        let row   = ds_masterHeader.insertRow();
        let coCd  = m["acctDeptCd"];
        let coNm  = m["acctDeptNm"];
        let colNo = m["colNo"];
        ds_masterHeader.setCellData(row, "coCd", coCd);
        ds_masterHeader.setCellData(row, "coNm", coNm.substring(3));
        ds_masterHeader.setCellData(row, "seq" , Number(colNo));
    }
    ds_masterHeader.reform();
    ds_masterHeader.sort("seq", 0);    
    for(let i=0; i<ds_masterHeader.getRowCount(); i++) {
        let coNm = ds_masterHeader.getCellData(i, "coNm");
        let seq  = ds_masterHeader.getCellData(i, "seq");
        gr_master.setHeaderValue("h_col"+seq, coNm);
        gr_master.setColumnVisible("col"+seq, true);
    }
    //총계가 아닌 경우는 소계 보여주기
    if(rd_srchBookKndCd.getValue() != "613" ) {
        gr_master.setColumnVisible("subTotal", true);
    }

    /**
     * 2. ds_master 데이터 → ds_crossTab 변환
     */
    ds_crossTab.removeAll();
    let temp = {};
    //부서별 금액 넣기    
    mData.forEach(function(row){
        let gCd    = row.asetCostCd;
        let gNm    = row.asetCostCdNm.substring(5);
        let dept   = row.acctDeptCd;
        let page   = row.pageNo;
        let col    = row.colNo;
        let amt = Number(row.asetCostAmt) || 0;
        if (!temp[gCd]) {
            temp[gCd] = { asetCostCd:gCd, asetCostCdNm:gNm, acctDeptCd:dept, pageNo:page, colNo:col, data: {} };
        }
        if (!temp[gCd].data[dept]) {
            temp[gCd].data[dept] = 0;
        }
        temp[gCd].data[dept] += amt;
    });

    //부서정보가져오기 col1, col2 col3에 값 넣을 부서
    let deptListRaw = ds_masterHeader.getAllJSON();
    let deptMap = {};
    let deptList = [];
    //부서중복제거
    deptListRaw.forEach(function(dept){
        if(!deptMap[dept.coCd]){
            deptMap[dept.coCd] = true;
            deptList.push(dept);
        }
    });

    //최종 결과 배열 생성
    let result = [];
    Object.keys(temp).forEach(function(gCd){
        let groupObj = temp[gCd];
        let row = {
            asetCostCd  : groupObj.asetCostCd,
            asetCostCdNm: groupObj.asetCostCdNm,
            acctDeptCd  : groupObj.acctDeptCd,
            pageNo      : groupObj.pageNo,
            colNo       : groupObj.colNo
        };
//console.log("gCd : "+gCd + ", groupObj : "+JSON.stringify(groupObj));
        let total = 0;
        // 부서 DataList 기준으로 col1, col2… 생성
        deptList.forEach(function(dept, idx){
                let col = "col" + (idx + 1);
                let coCd = dept.coCd;   // 부서 코드 꺼내기
                let val = groupObj.data[coCd] || 0; // 값 없으면 0
                row[col] = val;
                total += val;
            //}
        });
        //그룹별 소계계산
        row.subTotal = total;

        result.push(row);
    });

    ds_crossTab.setJSON(result);
    ds_crossTab.reform();
};

/**
 * 팝업
 * TOBE 사용안함
 */
scwin.f_PopUp = function (paramArray) {
    var codeObj = paramArray.pCode;
    var nameObj = paramArray.pName;

    rtnList = cfCommonPopUp(paramArray.pSelectID, $c.gus.cfGetValue(codeObj), ""
        , scwin.f_EventCheck(), paramArray.pDispCnt
        , paramArray.pTitle, paramArray.pWidth
        , paramArray.pHidden, paramArray.pWhere
        , paramArray.pW, paramArray.pH
        , paramArray.pTop, paramArray.pLeft
        , paramArray.pExistTF, paramArray.pAllSearchTF
        , paramArray.pWtitleSearch)
    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            $c.gus.cfSetValue(codeObj, rtnList[0]);
            codeObj.hidVal = rtnList[0];
            $c.gus.cfSetValue(nameObj, rtnList[1]);
        }
    } else {
        $c.gus.cfSetValue(codeObj, "");
        codeObj.hidVal = "";
        $c.gus.cfSetValue(nameObj, "");
    }

    return rtnList;
};

/**
 * 팝업여부검사
 * TOBE 사용안함
 */
scwin.f_IsPopUp = function (inObj) {
    var inValue = $c.gus.cfGetValue(inObj);
    var hidValue = inObj.hidVal;

    if ($c.gus.cfIsNull(inValue)) {
        inObj.hidVal = "";
        for (var i = 1; i < f_IsPopUp.arguments.length; i++) {
            $c.gus.cfSetValue(f_IsPopUp.arguments[i], "");
        }
        return false;
    }
    if (inValue == hidValue) return false;

    return true;
};

/**
 * 팝업 이벤트에 따라 팝업창의 자동닫기 여부를 반환
 * TOBE : 사용안함
 */
scwin.f_EventCheck = function() {   
    //if (window.event != null && window.event.srcElement.tagName.toUpperCase() == "IMG") {
    if (window.event != null && window.event.srcElement.tagName.toUpperCase() == "btn_") {
        return 'F';
    } else {
        return 'T';
    }
};


