/**
 * 페이지정보를 표시한다.
 * TOBE 사용안함(PageList 컴포넌트 사용)
 */
scwin.f_DisplayPaging = function() {
    var pagingStr = "<table width='100%' border='0' cellpadding='2' cellspacing='1'>"
        + "<tr>"
        + " <td align='center' class='pagenumber_td'>";

    for (var i = 1; i <= ds_page.getRowCount(); i++) {
        page = ds_page.getCellData(i, "COL1");
        if (page != scwin.currentPage)
            pagingStr += "<a href='#' onClick=scwin.f_MoveToPage('" + page + "')>&nbsp;" + page + "&nbsp;</a>";
        else
            pagingStr += '&nbsp;[' + page + ']&nbsp;';
    }
    pagingStr += " </td>"
        + "</tr>"
        + "</table>";

    pagingIndex.innerHTML = pagingStr
};

