/**
 * 그리드 데이터 엑셀로 다운
 */
scwin.f_Export = async function () {
    let totCnt = ds_master.getRowCount();
    if (totCnt < 1 ) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다
        return;
    }
    let sheetTitle = "자산비용실적_"+rd_srchBookKndCd.getText() + "_" + ica_srchStdYm.getValue() + "_ver_" + lc_version.getValue()
    let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
        let options = {
            fileName: sheetTitle+".xlsx",
            sheetName: sheetTitle,
            type: "2",
            headerColor: "#d9d9d9", //"#E8E8E8", //연한회색 #33CCCC
            startRowIndex: 0
        };
        //그리드에 대한 내용을 추가 옵션
        // let infoArr = [
        //     //제목
        //     {
        //         rowIndex: 0               //제목을 표시할 행 index
        //         , colIndex: 0               //제목을 표시할 열 index
        //         , rowSpan: 1                //병합할 행의 수
        //         , colSpan: 25               //병합할 열의 수
        //         , text: sheetTitle          //표시할 내용(제목)
        //         , textAlign: "center"       //표시할 내용의 정렬 방법(left, center, right)
        //         , fontSize: "12px"          //폰트 size
        //         , fontName: "돋움체"        //폰트이름 
        //         , drawBorder: false         //cell의 border 지정(true, false)
        //     }
        // ];
        $c.data.downloadGridViewExcel(gr_master, options);
    }
};

